#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long evenSum = 0, oddSum = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            if (i % 2 == 0) evenSum += x; else oddSum += x;
        }
        printf("%lld\n", evenSum - oddSum);
    }
    return 0;
}

