import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        even_sum = 0
        odd_sum = 0
        for i in range(N):
            x = int(next(it))
            if i % 2 == 0:
                even_sum += x
            else:
                odd_sum += x
        out_lines.append(str(even_sum - odd_sum))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

